const provinceIdByName = new Map(PROVINCES.map((p) => [p.name, p.id]));

export function districtsOf(provinceName: string): Loc[] {
  const id = provinceIdByName.get(provinceName);
  return id ? DISTRICTS_BY_PROVINCE[id] ?? [] : [];
}

export function districtIdOf(provinceName: string, districtName: string): string | undefined {
  return districtsOf(provinceName).find((d) => d.name === districtName)?.id;
}

// Villages: lazy-loaded once, cached. Stored as compact [id, name, lo] tuples.
type VillageTuple = [string, string, string];
let _villages: Record<string, VillageTuple[]> | null = null;

export async function ensureVillages(): Promise<Record<string, VillageTuple[]>> {
  if (!_villages) {
    const mod = await import("./laoVillages.json");
    _villages = (mod.default ?? mod) as unknown as Record<string, VillageTuple[]>;
  }
  return _villages;
}

export async function villagesOf(provinceName: string, districtName: string): Promise<Loc[]> {
  const did = districtIdOf(provinceName, districtName);
  if (!did) return [];
  const all = await ensureVillages();
  return (all[did] ?? []).map(([id, name, lo]) => ({ id, name, lo }));
}
